INSERT INTO public.email_templates (id, template_key, name, subject, body_html, description, variables, created_at, updated_at) VALUES
('11d55ef4-4bac-4356-af9d-458a3d0ad08a', 'task_assigned', 'Task assigned', 'New task assigned: {{task_title}}', '<p>Hi {{employee_name}},</p><p>A new task has been assigned to you on Amazon Jobs Portal.</p><div style="background:#f7f8fa;border:1px solid #e7e7e7;border-radius:8px;padding:14px;margin:14px 0"><div style="font-weight:700;font-size:16px;margin-bottom:6px">{{task_title}}</div><div style="font-size:13px;color:#565959;white-space:pre-wrap">{{task_description}}</div><div style="margin-top:10px;font-size:12px"><b>Reward:</b> ₹{{reward_amount}} · <b>Deadline:</b> {{deadline}}</div></div><p style="margin:14px 0"><a href="{{task_url}}" style="background:#FF9900;color:#0F1111;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:bold">Open task</a></p>', 'Sent when an admin assigns a new task to an employee.', '{"employee_name","task_title","task_description","reward_amount","deadline","task_url"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('1d1d942f-0de9-4500-9196-0ad5c403cd6e', 'task_due_soon', 'Task due soon', 'Reminder: "{{task_title}}" is due soon', '<p>Hi {{employee_name}},</p><p>This is a friendly reminder that your task <b>{{task_title}}</b> is due on <b>{{deadline}}</b>.</p><p>Reward on approval: <b>₹{{reward_amount}}</b></p><p style="margin:14px 0"><a href="{{task_url}}" style="background:#FF9900;color:#0F1111;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:bold">Open task</a></p>', 'Sent automatically when a task deadline is within 24 hours.', '{"employee_name","task_title","reward_amount","deadline","task_url"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('cf76bff8-a5af-44bb-8c2e-3553d5de083f', 'task_overdue', 'Task overdue', 'Overdue: {{task_title}}', '<p>Hi {{employee_name}},</p><p>Your task <b>{{task_title}}</b> was due <b>{{deadline}}</b> and is now <b style="color:#b12704">overdue</b>. Please submit it as soon as possible.</p><p>Reward on approval: <b>₹{{reward_amount}}</b></p><p style="margin:14px 0"><a href="{{task_url}}" style="background:#b12704;color:#fff;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:bold">Submit task now</a></p>', 'Sent automatically when a task passes its deadline without submission.', '{"employee_name","task_title","reward_amount","deadline","task_url"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('de40507b-c3d7-4f72-888e-1b62dbbab68c', 'kyc_documents_submitted', 'KYC — documents submitted', 'KYC received — under review', '<p>Hi {{employee_name}},</p><p>Thanks — we''ve received your KYC submission and your security deposit payment.</p><p>Our team will verify your documents within 24 hours and email you with the outcome.</p><p style="font-size:12px;color:#565959">Payment reference: <b>{{payment_reference}}</b></p>', 'Sent when an employee completes KYC submission with payment.', '{"employee_name","payment_reference"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('33211e34-aec8-4b15-be10-5d6a4dd52c1e', 'kyc_fee_paid', 'KYC — fee paid', 'Payment received for KYC verification', '<p>Hi {{employee_name}},</p><p>We''ve received your KYC processing fee of <b>${{fee_amount}}</b>. Your submission will move into review shortly.</p><p style="font-size:12px;color:#565959">Payment reference: <b>{{payment_reference}}</b></p>', 'Sent when the KYC fee payment is recorded.', '{"employee_name","fee_amount","payment_reference"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('40a83504-101e-4310-a160-4e1cb2f2ec61', 'kyc_in_review', 'KYC — review in progress', 'Your KYC is now in review', '<p>Hi {{employee_name}},</p><p>An admin has started reviewing your KYC documents. You''ll receive another email shortly with the final decision.</p>', 'Sent when an admin opens the submission for active review.', '{"employee_name"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('548f15c4-4741-49e4-9f8e-f526df6516c6', 'kyc_approved', 'KYC — approved', 'Your KYC has been approved 🎉', '<p>Hi {{employee_name}},</p><p>Great news — your KYC verification has been <b style="color:#067d62">approved</b>. You can now request withdrawals from the dashboard.</p><p style="margin:14px 0"><a href="{{dashboard_url}}" style="background:#067d62;color:#fff;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:bold">Go to dashboard</a></p>', 'Sent when the admin approves the KYC submission.', '{"employee_name","dashboard_url"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('09a8fbcd-5a2c-414a-966c-ad0807ef4055', 'kyc_rejected', 'KYC — rejected', 'Update on your KYC submission', '<p>Hi {{employee_name}},</p><p>Unfortunately your KYC submission was <b style="color:#b12704">not approved</b>. Please review the note below, correct any issues, and resubmit.</p><div style="background:#f7f8fa;border-left:3px solid #b12704;padding:10px 14px;margin:14px 0;font-size:13px"><b>Reason:</b><br/>{{admin_notes}}</div><p style="margin:14px 0"><a href="{{kyc_url}}" style="background:#FF9900;color:#0F1111;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:bold">Resubmit KYC</a></p>', 'Sent when an admin rejects the KYC submission.', '{"employee_name","admin_notes","kyc_url"}', '2026-04-26 20:20:54.443792+00', '2026-04-26 20:20:54.443792+00'),
('419179bd-18e4-4c9e-a253-d2285fe6b566', 'module_assigned', 'Module assigned', 'You''ve been assigned to {{module_title}} on {{project_title}}', '<p>Hi {{employee_name}},</p><p>You''ve been added to the <b>{{module_title}}</b> module of project <b>{{project_title}}</b>.</p><p>{{module_description}}</p><p><a href="{{project_url}}" style="display:inline-block;background:#FF9900;color:#fff;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:700">Open project</a></p><p>Good luck!</p>', 'Sent when an admin assigns an employee to a project module.', '{"employee_name","module_title","project_title","module_description","project_url"}', '2026-04-26 20:21:40.436084+00', '2026-04-26 20:21:40.436084+00'),
('e7f44b5f-6dc8-4064-a6ad-48bd66f1bbce', 'task_comment_added', 'Task comment added', 'New comment on "{{task_title}}"', '<p>Hi {{employee_name}},</p><p><b>{{author_name}}</b> commented on your task <b>{{task_title}}</b>:</p><blockquote style="border-left:3px solid #FF9900;padding:6px 12px;color:#333;margin:12px 0">{{comment_body}}</blockquote><p><a href="{{task_url}}" style="display:inline-block;background:#FF9900;color:#fff;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:700">View task</a></p>', 'Sent when someone leaves a comment on a task you''re part of.', '{"employee_name","author_name","task_title","comment_body","task_url"}', '2026-04-26 20:21:40.436084+00', '2026-04-26 20:21:40.436084+00'),
('46335fcc-9e2d-442e-b1fa-af225127221f', 'task_changes_requested', 'Changes requested', 'Changes requested on "{{task_title}}"', '<p>Hi {{employee_name}},</p><p>Your reviewer has requested changes on <b>{{task_title}}</b>.</p><div style="background:#fff7ed;border-left:3px solid #FF9900;padding:10px 14px;margin:14px 0"><b>Feedback:</b><br/>{{review_notes}}</div><p>The task is back in your queue — make the updates and resubmit when ready.</p><p><a href="{{task_url}}" style="display:inline-block;background:#FF9900;color:#fff;padding:10px 18px;border-radius:6px;text-decoration:none;font-weight:700">Open task</a></p>', 'Sent when an admin requests changes on a submitted task.', '{"employee_name","task_title","review_notes","task_url"}', '2026-04-26 20:21:40.436084+00', '2026-04-26 20:21:40.436084+00')
